#!/usr/bin/env node

/**
 * Maestro Extension Skill Bundler
 * Reads all SKILL.md files from source/skills/ directories, parses frontmatter,
 * and generates src/generated/skills-data.ts for the VS Code extension.
 */

const fs = require('fs');
const path = require('path');

const ROOT = path.resolve(__dirname, '..', '..');
const SOURCE_DIR = path.join(ROOT, 'source', 'skills');
const OUTPUT_DIR = path.join(__dirname, '..', 'src', 'generated');
const OUTPUT_FILE = path.join(OUTPUT_DIR, 'skills-data.ts');

/**
 * Parse YAML frontmatter from a markdown file.
 */
function parseFrontmatter(raw) {
  const match = raw.match(/^---\r?\n([\s\S]*?)\r?\n---\r?\n([\s\S]*)$/);
  if (!match) {
    return { meta: {}, content: raw };
  }

  const meta = {};
  const yamlLines = match[1].split(/\r?\n/);
  for (const line of yamlLines) {
    const colonIdx = line.indexOf(':');
    if (colonIdx === -1) continue;
    const key = line.slice(0, colonIdx).trim();
    let value = line.slice(colonIdx + 1).trim();
    if ((value.startsWith('"') && value.endsWith('"')) ||
        (value.startsWith("'") && value.endsWith("'"))) {
      value = value.slice(1, -1);
    }
    if (value === 'true') value = true;
    else if (value === 'false') value = false;
    meta[key] = value;
  }

  return { meta, content: match[2].trim() };
}

/**
 * Escape a string for use inside a TypeScript template literal.
 */
function escapeForTemplateLiteral(str) {
  return str
    .replace(/\\/g, '\\\\')
    .replace(/`/g, '\\`')
    .replace(/\$\{/g, '\\${');
}

function bundle() {
  console.log('Maestro Extension Skill Bundler');
  console.log('===============================\n');

  if (!fs.existsSync(SOURCE_DIR)) {
    console.error('[ERR] Source directory not found:', SOURCE_DIR);
    process.exit(1);
  }

  const skillDirs = fs.readdirSync(SOURCE_DIR, { withFileTypes: true })
    .filter(d => d.isDirectory())
    .map(d => d.name)
    .sort();

  const skills = [];
  for (const dirName of skillDirs) {
    const skillFile = path.join(SOURCE_DIR, dirName, 'SKILL.md');
    if (!fs.existsSync(skillFile)) continue;

    const raw = fs.readFileSync(skillFile, 'utf-8');
    const { meta, content } = parseFrontmatter(raw);

    skills.push({
      name: meta.name || dirName,
      description: meta.description || '',
      category: meta.category || 'unknown',
      version: meta.version || '1.0.0',
      argumentHint: meta['argument-hint'] || undefined,
      userInvocable: meta['user-invocable'] === true,
      content,
    });

    console.log(`  [skill] ${meta.name || dirName} (${meta.category}, invocable=${meta['user-invocable']})`);
  }

  console.log(`\nTotal: ${skills.length} skills\n`);

  // Generate TypeScript
  let output = `// AUTO-GENERATED by maestro-extension/scripts/bundle-skills.js — DO NOT EDIT\n\n`;

  output += `export interface SkillData {\n`;
  output += `  name: string;\n`;
  output += `  description: string;\n`;
  output += `  category: string;\n`;
  output += `  version: string;\n`;
  output += `  argumentHint?: string;\n`;
  output += `  userInvocable: boolean;\n`;
  output += `  content: string;\n`;
  output += `}\n\n`;

  output += `export const skills: SkillData[] = [\n`;
  for (const skill of skills) {
    output += `  {\n`;
    output += `    name: ${JSON.stringify(skill.name)},\n`;
    output += `    description: ${JSON.stringify(skill.description)},\n`;
    output += `    category: ${JSON.stringify(skill.category)},\n`;
    output += `    version: ${JSON.stringify(skill.version)},\n`;
    if (skill.argumentHint) {
      output += `    argumentHint: ${JSON.stringify(skill.argumentHint)},\n`;
    }
    output += `    userInvocable: ${skill.userInvocable},\n`;
    output += `    content: \`${escapeForTemplateLiteral(skill.content)}\`,\n`;
    output += `  },\n`;
  }
  output += `];\n`;

  // Category metadata for the sidebar UI
  output += `\nexport const categories = [\n`;
  output += `  { id: "analysis", label: "Analysis", icon: "Search", skills: ["diagnose", "evaluate"] },\n`;
  output += `  { id: "fix", label: "Fix & Improve", icon: "Wrench", skills: ["refine", "streamline", "calibrate", "fortify", "zero-defect"] },\n`;
  output += `  { id: "enhancement", label: "Enhancement", icon: "Zap", skills: ["amplify", "chain", "compose", "enrich", "guard", "iterate", "accelerate", "turbocharge"] },\n`;
  output += `  { id: "utility", label: "Utility", icon: "Settings", skills: ["teach-maestro", "onboard-agent", "adapt-workflow", "specialize", "extract-pattern", "temper"] },\n`;
  output += `] as const;\n`;

  fs.mkdirSync(OUTPUT_DIR, { recursive: true });
  fs.writeFileSync(OUTPUT_FILE, output, 'utf-8');

  console.log(`[OK] Generated ${OUTPUT_FILE}`);
  console.log(`     ${skills.length} skills bundled`);
}

bundle();
